import re

# Load datasets from stored file paths
books_file = locals()['var_functions.query_db:44']
reviews_file = locals()['var_functions.query_db:36']

with open(books_file) as f:
    books = json.load(f)

with open(reviews_file) as f:
    reviews = json.load(f)

# Extract publication years using regex
year_pattern = re.compile(r'\b(19\d{2}|20\d{2})\b')

book_years = {}
for b in books:
    years = year_pattern.findall(b['details'])
    if years:
        year = int(min(years))
        book_years[b['book_id']] = (year // 10) * 10

# Group reviews by decade
decade_data = {}
for r in reviews:
    purchase_id = r['purchase_id']
    if purchase_id in book_years:
        decade = book_years[purchase_id]
        rating = float(r['rating'])

        if decade not in decade_data:
            decade_data[decade] = {'ratings': [], 'books': set()}

        decade_data[decade]['ratings'].append(rating)
        decade_data[decade]['books'].add(purchase_id)

# Find decade with highest avg rating (>= 10 books)
candidates = []
for decade, data in decade_data.items():
    book_count = len(data['books'])
    if book_count >= 10:
        avg = sum(data['ratings']) / len(data['ratings'])
        candidates.append((decade, avg, book_count))

candidates.sort(key=lambda x: x[1], reverse=True)

best = candidates[0][0] if candidates else None

output = {'decade': best, 'found': len(candidates)}
print('__RESULT__:')
print(json.dumps(output))"}

